#include<bits/stdc++.h>
using namespace std;
#define MAXN 100008

int main()
{
    int dir[MAXN] = {0};
    long long n, m, cur = 0, a, s;
    int i;
    string occ[MAXN];
    cin>>n>>m;
    for (i = 0; i < n; ++i) {
       cin>>dir[i]>>occ[i];
    }
    for (i = 0; i < m; ++i) {
        cin>>a>>s;
        if (dir[cur] == a)
        {
            s *= -1;
        }
        cur = (cur + n + s) % n;
    }
    cout<<occ[cur];
    return 0;
}
